// Add contact to both Resend audiences with properties
const email = $json['אימייל'];
const firstName = $json['שם'];
const phone = String($json['וואטסאפ'] || $json['טלפון'] || '');

const contactData = {
  email: email,
  first_name: firstName,
  unsubscribed: false
};

// Add to "All Subscribers" audience
const allSubs = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.resend.com/audiences/8d799f25-66f6-4906-8df7-61bea6e53774/contacts',
  headers: {
    'Authorization': 'Bearer ' + $env['RESEND_API_KEY'],
    'Content-Type': 'application/json'
  },
  body: JSON.stringify(contactData)
});

// Add to "Workshop Attendees" audience
const workshop = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.resend.com/audiences/d7938ef7-847c-42a9-bbe1-ca5c287d9d69/contacts',
  headers: {
    'Authorization': 'Bearer ' + $env['RESEND_API_KEY'],
    'Content-Type': 'application/json'
  },
  body: JSON.stringify(contactData)
});

return { json: { allSubs, workshop, email, firstName, phone } };
